  <svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Awesome-Oscillator-Histogramm: Trend vs. Korrektur (Konzeptionell)</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Differenz zwischen 5- und 34-Perioden-Durchschnitt (Histogramm) · illustratives Beispiel</text>
    <line x1="60" y1="234" x2="640" y2="234" stroke="#52525b" stroke-width="1.2"/>
    <text x="48" y="238" fill="#71717a" font-size="13" text-anchor="end" font-family="sans-serif">0</text>
    <line x1="345" y1="60" x2="345" y2="405" stroke="#3f3f46" stroke-dasharray="5,5"/>
